function base64ToArrayBuffer(base64: string): ArrayBuffer {
  let buffer = Buffer.from(base64, 'base64');
  return buffer.buffer.slice(
    buffer.byteOffset,
    buffer.byteOffset + buffer.byteLength,
  ) as ArrayBuffer;
}

const interBlackBase64 = "";
export const interBlack = base64ToArrayBuffer(interBlackBase64);

const interRegularBase64 = "";
export const interRegular = base64ToArrayBuffer(interRegularBase64);

